set search_path = ''
as $$
  select nullif(auth.jwt() ->> 'sub', '')::uuid
$$;

create or replace function public.current_user_role()
returns public.user_role
language sql
stable
set search_path = ''
as $$
  select nullif(auth.jwt() ->> 'role', '')::public.user_role
$$;

